/* ── Chevron icon — direction aware ── */
function Chevron({ open }) {
  return (
    <svg width="10" height="10" viewBox="0 0 16 10" fill="none" className="flex-shrink-0 ml-[4px]">
      <path
        d={open ? "M14 8l-6-6-6 6" : "M2 2l6 6 6-6"}
        stroke="#2F78C4"
        strokeWidth="2.2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

/* ── Sub-item row ── */
function SubItem({ label, count, slug }) {
  const [hovered, setHovered] = useState(false);
  const navigate = useNavigate();
  const clickable = !!slug;
  return (
    <div
      className="flex items-center justify-between px-[12px] py-[8px] transition-colors"
      style={{
        backgroundColor: hovered ? "#2F78C4" : "transparent",
        color: hovered ? "#ffffff" : "#000048",
        cursor: clickable ? "pointer" : "default",
      }}
      onMouseEnter={() => setHovered(true)}
      onMouseLeave={() => setHovered(false)}
      onClick={() => clickable && navigate(`/category/${slug}`)}
    >
      <span className="text-[12px] leading-[17px]">{label}</span>
      {slug && (() => {
        const n = CATEGORY_SOLUTIONS[slug]?.solutions?.length ?? count;
        return n ? <span className="text-[11px] font-semibold ml-[8px] flex-shrink-0" style={{ color: hovered ? "#ffffff" : "#6F6F6F" }}>{n}</span> : null;
      })()}
      {!slug && count != null && (
        <span className="text-[11px] font-semibold ml-[8px] flex-shrink-0" style={{ color: hovered ? "#ffffff" : "#6F6F6F" }}>
          {count}
        </span>
      )}
    </div>
  );
}

/* ── Card component ── */
function LayerCard({ card }) {
  const [expandedIndex, setExpandedIndex] = useState(null);
  const navigate = useNavigate();

  const toggleItem = (i) => setExpandedIndex(expandedIndex === i ? null : i);

  const agentCount = (() => {
    const allSlugs = card.items.flatMap(item => [
      item.slug,
      ...(item.subItems?.map(sub => sub.slug) ?? []),
    ]).filter(Boolean);
    const uniqueTitles = new Set();
    allSlugs.forEach(slug => {
      CATEGORY_SOLUTIONS[slug]?.solutions?.forEach(sol => uniqueTitles.add(sol.title));
    });
    return uniqueTitles.size;
  })();

  return (
    <div
      className="bg-white flex flex-col gap-[12px]"
      style={{
        borderRadius: 12,
        border: "1px solid #E2E8F0",
        boxShadow: "0 2px 10px rgba(0,0,72,0.08)",
        padding: "20px",
      }}
    >
      {/* Icon + title */}
      <div className="flex items-start gap-[12px]">
        {card.Icon && <card.Icon />}
        <div className="flex-1 min-w-0">
          <h3 className="font-bold text-[14px] leading-[20px]" style={{ color: "#000048" }}>
            {card.title}
          </h3>
          <p className="text-[11px] leading-[16px] mt-[4px]" style={{ color: "#53565A" }}>
            {card.subtitle}
          </p>
        </div>
      </div>

      {/* Agent badge */}
      {agentCount > 0 && (
        <div>
          <CardBadge count={agentCount} label={agentCount === 1 ? "Agent" : "Agents"} />
        </div>
      )}

      {/* Divider — always present for all cards */}
      <hr style={{ borderColor: "#E2E8F0", margin: 0 }} />

      {/* Items */}
      <ul className="flex flex-col gap-[6px]">
        {card.items.map((item, i) => (
          <li key={i}>
            {/* Parent row */}
            <div
              className="flex items-center justify-between px-[10px] py-[8px] rounded-[6px]"
              style={{
                backgroundColor: "#DEEEFF",
                cursor: (item.hasArrow || item.slug) ? "pointer" : "default",
              }}
              onClick={() => {
                if (item.hasArrow) toggleItem(i);
                else if (item.slug) navigate(`/category/${item.slug}`);
              }}
            >
              <span className="flex items-center gap-[8px]">
                <span
                  className="flex-shrink-0"
                  style={{ width: 5, height: 5, borderRadius: "50%", backgroundColor: "#2F78C4" }}
                />
                <span className="text-[12px] leading-[17px]" style={{ color: "#000048" }}>
                  {item.label}
                </span>
              </span>
              {item.slug && (() => {
                const n = CATEGORY_SOLUTIONS[item.slug]?.solutions?.length;
                return n ? <span className="text-[11px] font-semibold ml-auto flex-shrink-0" style={{ color: "#6F6F6F" }}>{n}</span> : null;
              })()}
              {item.hasArrow && (() => {
                const total = item.subItems?.reduce((sum, sub) =>
                  sum + (sub.slug ? (CATEGORY_SOLUTIONS[sub.slug]?.solutions?.length ?? 0) : 0), 0) ?? 0;
                return total > 0 ? <span className="text-[11px] font-semibold ml-auto flex-shrink-0" style={{ color: "#6F6F6F" }}>{total}</span> : null;
              })()}
              {item.hasArrow && <Chevron open={expandedIndex === i} />}
            </div>

            {/* Sub-items dropdown */}
            {item.hasArrow && expandedIndex === i && item.subItems?.length > 0 && (
              <div
                className="mt-[4px] overflow-hidden"
                style={{
                  border: "1px solid #92BBE6",
                  borderRadius: 6,
                }}
              >
                {item.subItems.map((sub, j) => (
                  <SubItem key={j} label={sub.label} count={sub.count} slug={sub.slug} />
                ))}
              </div>
            )}
          </li>
        ))}
      </ul>
    </div>
  );
}

